import 'package:baseball_detector_flutter/data/models/team.dart';
import '../record_definitions.dart';

const teamMultipleUsers = Team(
  id: '11111111-0001-0000-0000-000000000000',
  name: '通常チーム',
);

const teamPersonal = Team(
  id: '44444444-0001-0000-0000-000000000000',
  // NOTE: set null for single-user team
  // name: 'personal_user用チーム',
);

const teamNoRole = Team(
  id: '55555555-0001-0000-0000-000000000000',
  // NOTE: set null for single-user team
  // name: 'ロールなしユーザー用チーム',
);

const teamSuperAdmin = Team(
  id: '66666666-0001-0000-0000-000000000000',
  // NOTE: set null for single-user team
  // name: 'super_admin用チーム',
);

const teamWriteTest = Team(
  id: '77777777-0001-0000-0000-000000000000',
  name: 'To be edited',
);

final teamRecords = RecordDefinitions<Team>(
  table: 'teams',
  data: [
    teamMultipleUsers,
    teamPersonal,
    teamNoRole,
    teamSuperAdmin,
    teamWriteTest,
  ],
  columns: {
    'id': (e) => e.id,
    'name': (e) => e.name,
  },
);

