import { Injectable, Logger } from '@nestjs/common';
import _ from 'lodash';
import moment from 'moment';
import { IPostgresInterval } from 'postgres-interval';
import { EntityManager, In } from 'typeorm';

import { Coded, CodedMethod, Persistence } from '@/app/common/decorators';
import { QueryUtil } from '@/app/common/utils/query.util';
import { CodedInvalidArgumentException } from '@/app/exceptions/errors/coded-invalid-argument.exception';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';
import { Item } from '@/app/models/item';
import { TeamItemsWithCount, TeamType } from '@/app/models/team';
import { TeamItem } from '@/app/models/team-item';
import { TeamItemAiCoach } from '@/app/models/team-item-ai-coach';
import { TeamItemBall } from '@/app/models/team-item-ball';
import { TeamItemDistributionHistory } from '@/app/models/team-item-distribution-history';
import { BasePersistence } from '@/app/persistence/base-persistence';

type SearchHistoriesConditions = {
  itemId?: string;
  teamType?: TeamType;
  createdAtFrom?: Date;
  createdAtTo?: Date;
  orderBy?: 'created_at' | 'start_date';
  isOrderDesc?: boolean;
  page?: number;
  pageSize?: number;
};

type ConsumeTeamItemEntryParam = {
  teamId?: string;
  teamSubscriptionIds?: string[];
  teamItemIds?: string[];
  count: number;
  now?: Date;
  asOf?: Date;

  /**
   * The operation will be performed regardless of the startDate and endDate.
   * It is intended to be used when teamSubscriptionIds or teamItemIds are specified.
   */
  ignoreDate?: boolean;

  /**
   * It only simulates consuming items and returns a list of items that
   * would be consumed, without actually consuming them.
   */
  dryRun?: boolean;
};

/**
 * A persistence layer responsible for handling team_items related records.
 *
 * ### Item Consumption Order
 *
 * * Items are consumed in order of earliest expiration date first.
 * * If multiple items share the same expiration date, the one with the higher
 *   priority value is consumed first.
 *   * For `teamItemAiCoach`: ordered by `teamItemAiCoach.endDate` (ascending),
 *     then by `teamItemAiCoach.itemAiCoach.priority` (descending).
 *   * For `teamItemBall`: ordered by `teamItemBall.endDate` (ascending), then
 *     `by teamItemBall.itemBall.priority` (descending).
 *
 * ### Item Restoration Order
 *
 * * Items are restored in the reverse of the consumption order.
 * * The most recently used items (those with later expiration dates) are
 *   restored first.
 * * If multiple items share the same expiration date, the one with the lower
 *   priority value is restored first.
 */
@Coded('PTMI')
@Persistence()
@Injectable()
export class TeamItemsPersistence extends BasePersistence {
  private readonly logger = new Logger(TeamItemsPersistence.name);

  constructor() {
    super();
  }

  static readonly ERROR_CODES = {
    INSUFFICIENT_ITEMS: ErrorInfo.getBuilder('ISCI', 'insufficient_items'),
    ITEM_NOT_EXISTS: ErrorInfo.getBuilder('INE', 'item_not_exists'),
  };

  get EC() {
    return TeamItemsPersistence.ERROR_CODES;
  }

  private calculateEndDate(
    startDate: Date,
    endDate: Date,
    validityPeriod: IPostgresInterval | null,
  ) {
    if (validityPeriod) {
      return moment(startDate).add(validityPeriod.toISOString()).toDate();
    }
    return endDate;
  }

  @CodedMethod('STP')
  async createTeamItem(
    t: EntityManager,
    data: {
      teamId: string;
      itemId: string;
      teamSubscriptionId?: string;
      startDate: Date;
      endDate: Date;
      currentAiCoachUsage?: number;
      currentBallUsage?: number;
      terminatedAt?: Date;
      /**
       * Whether this is the latest item associated with the teamSubscription.
       * Usage is undefined if not linked to teamSubscription.
       */
      isLatest?: boolean;
    },
  ) {
    const cbuilder = this.getCodeBuilder();

    const item = await t.findOne(Item, {
      where: {
        id: data.itemId,
      },
      relations: {
        aiCoachs: true,
        balls: true,
      },
    });
    if (!item) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.ITEM_NOT_EXISTS(cbuilder.build()),
      );
    }

    const teamItem = await t.insert(TeamItem, {
      teamId: data.teamId,
      itemId: data.itemId,
      teamSubscriptionId: data.teamSubscriptionId,
      terminatedAt: data.terminatedAt,
      isLatest: data.isLatest,
    });
    await t.insert(
      TeamItemAiCoach,
      item.aiCoachs.map((aiCoach) => ({
        teamItemId: teamItem.identifiers[0].id,
        itemAiCoachId: aiCoach.id,
        startDate: data.startDate,
        endDate: this.calculateEndDate(
          data.startDate,
          data.endDate,
          aiCoach.validityPeriod,
        ),
      })),
    );
    await t.insert(
      TeamItemBall,
      item.balls.map((ball) => ({
        teamItemId: teamItem.identifiers[0].id,
        itemBallId: ball.id,
        startDate: data.startDate,
        endDate: this.calculateEndDate(
          data.startDate,
          data.endDate,
          ball.validityPeriod,
        ),
      })),
    );

    let consumedAiCoachs: { teamItemAiCoachId: string; count: number }[] = [];
    let consumedBalls: { teamItemBallId: string; count: number }[] = [];
    if (data.currentAiCoachUsage) {
      consumedAiCoachs = await this.consumeItemAiCoachs(t, {
        teamId: data.teamId,
        teamItemIds: [teamItem.identifiers[0].id],
        count: data.currentAiCoachUsage,
        ignoreDate: true,
      });
    }
    if (data.currentBallUsage) {
      consumedBalls = await this.consumeItemBalls(t, {
        teamId: data.teamId,
        teamItemIds: [teamItem.identifiers[0].id],
        count: data.currentBallUsage,
        ignoreDate: true,
      });
    }

    return {
      consumedAiCoachs,
      consumedBalls,
    };
  }

  /**
   * WARNING: This deletes TeamItems for testing and physical deletion.
   * Do not use under normal circumstances.
   */
  async deleteTeamItems(
    t: EntityManager,
    param: {
      teamItemIds?: string[];
      teamId?: string;
      teamSubscriptionIds?: string[];
    },
  ) {
    // Safety guard: If no conditions are specified, all items will be deleted,
    // so this prevents that dangerous behavior.
    if (_.isEmpty(param)) {
      this.logger.warn('deleteTeamItems called with no parameters');
      return;
    }

    const teamItems = await t.getRepository(TeamItem).find({
      select: {
        teamItemAiCoachs: {
          id: true,
        },
        teamItemBalls: {
          id: true,
        },
      },
      where: {
        id: param.teamItemIds ? In(param.teamItemIds) : undefined,
        teamId: param.teamId,
        teamSubscriptionId: param.teamSubscriptionIds
          ? In(param.teamSubscriptionIds)
          : undefined,
      },
      relations: {
        teamItemAiCoachs: true,
        teamItemBalls: true,
      },
    });
    const teamItemIds = teamItems.map((teamItem) => teamItem.id);
    const teamItemAiCoachIds = teamItems
      .map((teamItem) =>
        teamItem.teamItemAiCoachs.map((teamItemAiCoach) => teamItemAiCoach.id),
      )
      .flat();
    const teamItemBallIds = teamItems
      .map((teamItem) =>
        teamItem.teamItemBalls.map((teamItemBall) => teamItemBall.id),
      )
      .flat();

    if (!_.isEmpty(teamItemAiCoachIds)) {
      await t.delete(TeamItemAiCoach, teamItemAiCoachIds);
    }
    if (!_.isEmpty(teamItemBallIds)) {
      await t.delete(TeamItemBall, teamItemBallIds);
    }
    if (!_.isEmpty(teamItemIds)) {
      await t.delete(TeamItem, teamItemIds);
    }
  }

  async consumeItemBalls(t: EntityManager, param: ConsumeTeamItemEntryParam) {
    const used: { teamItemBallId: string; count: number }[] = [];

    for (const date of [
      ...(param.asOf && !param.ignoreDate ? [param.asOf] : []),
      param.now ?? new Date(),
    ]) {
      const qb = t
        .createQueryBuilder(TeamItemBall, 'tib')
        .leftJoin('tib.teamItem', 'ti')
        .leftJoinAndSelect('tib.itemBall', 'ib')
        .where('ti.terminatedAt IS NULL')
        .orderBy('tib.endDate', 'ASC')
        .addOrderBy('ib.priority', 'DESC');

      if (!_.isNil(param.teamId)) {
        qb.andWhere('ti.teamId = :teamId', { teamId: param.teamId });
      }
      if (!_.isEmpty(param.teamItemIds)) {
        qb.andWhere('ti.id IN (:...teamItemIds)', {
          teamItemIds: param.teamItemIds,
        });
      }
      if (!_.isEmpty(param.teamSubscriptionIds)) {
        qb.andWhere('ti.teamSubscriptionId IN (:...teamSubscriptionIds)', {
          teamSubscriptionIds: param.teamSubscriptionIds,
        });
      }
      if (!param.ignoreDate) {
        qb.setParameter('date', date)
          .andWhere('tib.startDate <= :date')
          .andWhere('tib.endDate > :date');
      }

      const teamItemBalls = await qb.getMany();

      let count = param.count;
      for (const teamItemBall of teamItemBalls) {
        const availableCount = Math.min(
          count,
          Math.max(
            0,
            teamItemBall.itemBall.availableCount - teamItemBall.currentUsage,
          ),
        );
        if (availableCount === 0) {
          continue;
        }

        if (!param.dryRun) {
          await t.update(
            TeamItemBall,
            { id: teamItemBall.id },
            {
              currentUsage: teamItemBall.currentUsage + availableCount,
            },
          );
        }

        used.push({
          teamItemBallId: teamItemBall.id,
          count: availableCount,
        });
        count -= availableCount;
        if (count <= 0) {
          return used;
        }
      }
    }

    return used;
  }

  private async findTeamItemAiCoachs(
    t: EntityManager,
    param: ConsumeTeamItemEntryParam,
    date: Date,
  ) {
    const qb = t
      .createQueryBuilder(TeamItemAiCoach, 'tia')
      .leftJoin('tia.teamItem', 'ti')
      .leftJoinAndSelect('tia.itemAiCoach', 'ia')
      .where('ti.terminatedAt IS NULL')
      .orderBy('tia.endDate', 'ASC')
      .addOrderBy('ia.priority', 'DESC');

    if (!_.isNil(param.teamId)) {
      qb.andWhere('ti.teamId = :teamId', { teamId: param.teamId });
    }
    if (!_.isEmpty(param.teamItemIds)) {
      qb.andWhere('ti.id IN (:...teamItemIds)', {
        teamItemIds: param.teamItemIds,
      });
    }
    if (!_.isEmpty(param.teamSubscriptionIds)) {
      qb.andWhere('ti.teamSubscriptionId IN (:...teamSubscriptionIds)', {
        teamSubscriptionIds: param.teamSubscriptionIds,
      });
    }
    if (!param.ignoreDate) {
      qb.setParameter('date', date)
        .andWhere('tia.startDate <= :date')
        .andWhere('tia.endDate > :date');
    }

    return qb.getMany();
  }

  async consumeItemAiCoachs(
    t: EntityManager,
    param: ConsumeTeamItemEntryParam,
  ) {
    const used: { teamItemAiCoachId: string; count: number }[] = [];

    for (const date of [
      ...(param.asOf && !param.ignoreDate ? [param.asOf] : []),
      param.now ?? new Date(),
    ]) {
      const teamItemAiCoachs = await this.findTeamItemAiCoachs(t, param, date);

      let count = param.count;
      for (const teamItemAiCoach of teamItemAiCoachs) {
        const availableCount = Math.min(
          count,
          Math.max(
            0,
            teamItemAiCoach.itemAiCoach.availableCount -
              teamItemAiCoach.currentUsage,
          ),
        );
        if (availableCount === 0) {
          continue;
        }

        if (!param.dryRun) {
          await t.update(
            TeamItemAiCoach,
            { id: teamItemAiCoach.id },
            {
              currentUsage: teamItemAiCoach.currentUsage + availableCount,
            },
          );
        }

        used.push({
          teamItemAiCoachId: teamItemAiCoach.id,
          count: availableCount,
        });
        count -= availableCount;
        if (count <= 0) {
          return used;
        }
      }
    }

    return used;
  }

  async restoreItemAiCoachs(
    t: EntityManager,
    param: ConsumeTeamItemEntryParam,
  ) {
    const restored: { teamItemAiCoachId: string; count: number }[] = [];

    for (const date of [
      ...(param.asOf && !param.ignoreDate ? [param.asOf] : []),
      param.now ?? new Date(),
    ]) {
      const teamItemAiCoachs = await this.findTeamItemAiCoachs(t, param, date);
      teamItemAiCoachs.reverse();

      let count = param.count;
      for (const teamItemAiCoach of teamItemAiCoachs) {
        const restorableCount = Math.min(
          count,
          Math.max(0, teamItemAiCoach.currentUsage),
        );
        if (restorableCount === 0) {
          continue;
        }

        if (!param.dryRun) {
          await t.update(
            TeamItemAiCoach,
            { id: teamItemAiCoach.id },
            {
              currentUsage: Math.max(
                0,
                teamItemAiCoach.currentUsage - restorableCount,
              ),
            },
          );
        }

        restored.push({
          teamItemAiCoachId: teamItemAiCoach.id,
          count: restorableCount,
        });
        count -= restorableCount;
        if (count <= 0) {
          return restored;
        }
      }
    }

    return restored;
  }

  @CodedMethod('VTIAA')
  async verifyTeamItemAiCoachAvailability(
    t: EntityManager,
    param: ConsumeTeamItemEntryParam,
  ) {
    const cbuilder = this.getCodeBuilder();

    const consumedAiCoachs = await this.consumeItemAiCoachs(t, {
      ...param,
      dryRun: true,
    });
    const consumedCount = consumedAiCoachs
      .map((e) => e.count)
      .reduce((p, c) => p + c, 0);
    if (consumedCount < param.count) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.INSUFFICIENT_ITEMS(cbuilder.build()),
      );
    }
  }

  @CodedMethod('VTIBA')
  async verifyTeamItemBallAvailability(
    t: EntityManager,
    param: ConsumeTeamItemEntryParam,
  ) {
    const cbuilder = this.getCodeBuilder();

    const consumedBalls = await this.consumeItemBalls(t, {
      ...param,
      dryRun: true,
    });
    const consumedCount = consumedBalls
      .map((e) => e.count)
      .reduce((p, c) => p + c, 0);
    if (consumedCount < param.count) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.INSUFFICIENT_ITEMS(cbuilder.build()),
      );
    }
  }

  async getTeamItemCounts(
    t: EntityManager,
    teamIds: string[],
  ): Promise<{
    [teamId: string]: TeamItemsWithCount;
  }> {
    const teamItems = await t.find(TeamItem, {
      where: { teamId: In(teamIds) },
      relations: {
        teamItemAiCoachs: {
          itemAiCoach: true,
        },
        teamItemBalls: {
          itemBall: true,
        },
      },
    });
    const result: {
      [teamId: string]: TeamItemsWithCount;
    } = {};
    const now = new Date();
    for (const teamItem of teamItems) {
      // 既に有効期限が切れている場合、またはサブスクリプションに紐づくteamItemの場合は除外
      if (teamItem.terminatedAt || teamItem.teamSubscriptionId) {
        continue;
      }

      const aiCoachUsage = teamItem.teamItemAiCoachs
        .filter((t) => t.endDate > now && t.startDate < now)
        .reduce((p, c) => p + c.currentUsage, 0);
      const ballUsage = teamItem.teamItemBalls
        .filter((t) => t.endDate > now && t.startDate < now)
        .reduce((p, c) => p + c.currentUsage, 0);
      const aiCoachAvailableCount = teamItem.teamItemAiCoachs
        .filter((t) => t.endDate > now && t.startDate < now)
        .reduce((p, c) => p + c.itemAiCoach.availableCount, 0);
      const ballAvailableCount = teamItem.teamItemBalls
        .filter((t) => t.endDate > now && t.startDate < now)
        .reduce((p, c) => p + c.itemBall.availableCount, 0);

      if (!result[teamItem.teamId]) {
        result[teamItem.teamId] = {
          teamItems: [],
          aiCoachUsage: 0,
          ballUsage: 0,
          aiCoachAvailableCount: 0,
          ballAvailableCount: 0,
        };
      }

      result[teamItem.teamId].teamItems.push(teamItem);
      result[teamItem.teamId].aiCoachUsage += aiCoachUsage;
      result[teamItem.teamId].ballUsage += ballUsage;
      result[teamItem.teamId].aiCoachAvailableCount += aiCoachAvailableCount;
      result[teamItem.teamId].ballAvailableCount += ballAvailableCount;
    }
    return result;
  }

  /**
   * Attach a new team item to teams.
   * @param t - The entity manager.
   * @param data - The data to attach the team item to the teams.
   * @param distributionHistoryId - The distribution history id. If we record the distribution history, we should attach the team item to the distribution history.
   * @returns The team item ids.
   */
  @CodedMethod('ATTT')
  async attachNewTeamItemToTeams(
    t: EntityManager,
    data: {
      teamIds: string[];
      item: Item;
      startDate: Date;
      endDate: Date;
    },
    distributionHistoryId?: string,
  ) {
    const cbuilder = this.getCodeBuilder();

    if (_.isEmpty(data.teamIds)) {
      return {
        teamItemIds: [],
      };
    }

    const teamItems = await t.insert(
      TeamItem,
      data.teamIds.map((teamId) => ({
        teamId,
        itemId: data.item.id,
        startDate: data.startDate,
        endDate: data.endDate,
        teamItemDistributionHistoryId: distributionHistoryId || null,
      })),
    );

    const insertTeamItemAiCoachs = teamItems.identifiers.flatMap(
      (identifier) => {
        return data.item.aiCoachs.map((aiCoach) => {
          return {
            teamItemId: identifier.id,
            itemAiCoachId: aiCoach.id,
            startDate: data.startDate,
            endDate: this.calculateEndDate(
              data.startDate,
              data.endDate,
              aiCoach.validityPeriod,
            ),
          };
        });
      },
    );
    const insertTeamItemBalls = teamItems.identifiers.flatMap((identifier) => {
      return data.item.balls.map((ball) => {
        return {
          teamItemId: identifier.id,
          itemBallId: ball.id,
          startDate: data.startDate,
          endDate: this.calculateEndDate(
            data.startDate,
            data.endDate,
            ball.validityPeriod,
          ),
        };
      });
    });
    // データがチーム数に応じて多くなるため、1000件ずつに分割して Insert する
    const aiCoachBulkInsertUnit = _.chunk(insertTeamItemAiCoachs, 1000);
    const ballBulkInsertUnit = _.chunk(insertTeamItemBalls, 1000);
    for (const aiCoachBulkInsert of aiCoachBulkInsertUnit) {
      await t.insert(TeamItemAiCoach, aiCoachBulkInsert);
    }
    for (const ballBulkInsert of ballBulkInsertUnit) {
      await t.insert(TeamItemBall, ballBulkInsert);
    }
    return {
      teamItemIds: teamItems.identifiers.map((identifier) => identifier.id),
    };
  }

  @CodedMethod('STIDH')
  async searchHistories(
    t: EntityManager,
    conditions: SearchHistoriesConditions,
  ): Promise<{ historyIds: string[]; total: number }> {
    const orderByColumn = {
      created_at: 'history.created_at',
      start_date: 'history.start_date',
    }[conditions.orderBy ?? 'created_at'];

    const qb = t.createQueryBuilder(TeamItemDistributionHistory, 'history');

    if (conditions.itemId) {
      qb.andWhere('history.item_id = :itemId', { itemId: conditions.itemId });
    }

    if (conditions.teamType) {
      qb.andWhere('history.team_type = :teamType', {
        teamType: conditions.teamType,
      });
    }

    if (conditions.createdAtFrom) {
      qb.andWhere('history.created_at >= :createdAtFrom', {
        createdAtFrom: conditions.createdAtFrom,
      });
    }

    if (conditions.createdAtTo) {
      qb.andWhere('history.created_at <= :createdAtTo', {
        createdAtTo: conditions.createdAtTo,
      });
    }

    qb.orderBy(
      orderByColumn ?? 'history.created_at',
      conditions.isOrderDesc ? 'DESC' : 'ASC',
    );

    if (conditions.pageSize) {
      qb.take(conditions.pageSize);
      qb.skip((conditions.page ?? 0) * conditions.pageSize);
    }

    const [histories, total] = await qb.getManyAndCount();

    return {
      historyIds: histories.map((history) => history.id),
      total,
    };
  }

  async getHistories(
    t: EntityManager,
    ids: string[],
  ): Promise<TeamItemDistributionHistory[]> {
    if (!ids.length) {
      return [];
    }
    const histories = await t.find(TeamItemDistributionHistory, {
      where: {
        id: In(ids),
      },
    });

    return QueryUtil.sortByOriginalIds(histories, ids);
  }
}

