import {
  Body,
  Controller,
  Delete,
  Get,
  Header,
  Logger,
  Param,
  ParseUUIDPipe,
  Post,
  Put,
  Query,
  Req,
  UseGuards,
} from '@nestjs/common';
import { ApiOperation } from '@nestjs/swagger';

import {
  ApiDefault,
  Authorized,
  Coded,
  CodedMethod,
} from '@/app/common/decorators';
import { AppExtendedRequest } from '@/app/common/types';
import { ValidationUtil } from '@/app/common/utils/validation.util';
import { BaseController } from '@/app/controllers/base-controller';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';
import { SuperAdminAccessGuard } from '@/app/guards/super-admin-access.guard';
import {
  PlayerSearchMultiTeamsDto,
  playerSearchMultiTeamsDtoValidator,
} from '@/app/models/dto/player.dto';
import {
  MultiTeamsResourceSearchDto,
  multiTeamsResourceSearchDtoValidator,
} from '@/app/models/dto/resource.dto';
import {
  LocationSearchDto,
  locationSearchDtoValidator,
  SessionSearchDto,
  sessionSearchDtoValidator,
} from '@/app/models/dto/session.dto';
import {
  teamAndUserCreateDtoValidator,
  TeamCreateDto,
  teamCreateDtoValidatorPreChecking,
  TeamItemCreateDto,
  teamItemCreateDtoValidator,
  TeamItemDistributionHistorySearchDto,
  teamItemDistributionHistorySearchDtoValidator,
  TeamPlanCreateDto,
  teamPlanCreateDtoValidator,
  TeamPlanUpdateDto,
  teamPlanUpdateDtoValidator,
  TeamSearchDto,
  teamSearchDtoValidator,
} from '@/app/models/dto/team.dto';
import { PlayersService } from '@/app/services/players.service';
import { ResourcesService } from '@/app/services/resources.service';
import { SessionsService } from '@/app/services/sessions.service';
import { TeamItemService } from '@/app/services/team-item.service';
import { TeamsService } from '@/app/services/teams.service';
import { UsersService } from '@/app/services/users.service';

@Coded('CTMAD')
@ApiDefault()
@Authorized()
@Controller('teams') // Caution: global team access (@Controller('teams')) is not acceptable except for super admins
export class TeamAdminsController extends BaseController {
  private readonly logger = new Logger(TeamAdminsController.name);

  constructor(
    private readonly teamsService: TeamsService,
    private readonly usersService: UsersService,
    private readonly sessionsService: SessionsService,
    private readonly resourcesService: ResourcesService,
    private readonly playersService: PlayersService,
    private readonly teamItemService: TeamItemService,
  ) {
    super();
  }

  static ERROR_CODES = {
    INVALID_ROLE: ErrorInfo.getBuilder('IR', 'invalid_role_for_this_user'),
  };

  get EC() {
    return TeamAdminsController.ERROR_CODES;
  }

  @ApiOperation({
    summary: '[superuser][admin,read] Searches teams (for super admins)',
    description: '',
    tags: ['team'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'read'))
  @CodedMethod('STM')
  @Post('search')
  async searchTeams(
    @Req() req: AppExtendedRequest,
    @Body() dto: TeamSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(teamSearchDtoValidator(), dto);

    const result = await this.teamsService.searchTeams(validated);

    return {
      teams: result.teams,
      total: result.total,
    };
  }

  @ApiOperation({
    summary:
      '[superuser][admin,read] Gets locations of all sessions of all teams',
    description: '',
    tags: ['session'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'read'))
  @CodedMethod('LS')
  @Get('sessions/locations')
  async getAllLocations(
    @Req() req: AppExtendedRequest,
    @Query() dto: LocationSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      locationSearchDtoValidator(),
      dto,
    );

    const result = await this.sessionsService.getLocations(validated, {});

    return {
      locations: result.locations,
    };
  }

  @ApiOperation({
    summary: '[superuser][admin,read] Search sessions (for super admins)',
    description: '',
    tags: ['session'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'read'))
  @CodedMethod('SSS')
  @Post('sessions/search')
  async searchSessions(
    @Req() req: AppExtendedRequest,
    @Body() dto: SessionSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(sessionSearchDtoValidator(), dto);

    const result = await this.sessionsService.searchSessions(
      validated,
      {},
      true,
      false,
    );

    return {
      sessions: result.sessions,
      total: result.total,
    };
  }

  @ApiOperation({
    summary: '[superuser][admin,read] Lists resources of all teams',
    description: '',
    tags: ['resource'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'read'))
  @CodedMethod('STRSS')
  @Post('resources/search')
  async searchTeamResources(
    @Req() req: AppExtendedRequest,
    @Body() dto: MultiTeamsResourceSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid, roleChecker } = req.appExtension.auth!;

    const validated = ValidationUtil.validate(
      multiTeamsResourceSearchDtoValidator(),
      dto,
    );

    const { resources, total } =
      await this.resourcesService.searchResourcesForMultiTeams(validated);

    return {
      resources,
      total,
    };
  }

  @ApiOperation({
    summary: '[superuser][admin,read] Search players (for super admins)',
    description: '',
    tags: ['player'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'read'))
  @CodedMethod('SPLY')
  @Post('players/search')
  async searchPlayers(
    @Req() req: AppExtendedRequest,
    @Body() dto: PlayerSearchMultiTeamsDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      playerSearchMultiTeamsDtoValidator(),
      dto,
    );

    const result =
      await this.playersService.searchPlayersForMultipleTeams(validated);

    return {
      players: result.players,
      total: result.total,
    };
  }

  @ApiOperation({
    summary: '[superuser][admin,write] Creates a team (for super admins)',
    description: '',
    tags: ['team'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'write'))
  @CodedMethod('CTM')
  @Post()
  async createNewTeam(
    @Req() req: AppExtendedRequest,
    @Body() dto: TeamCreateDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid } = req.appExtension.auth!;

    const validatedDataBasic = ValidationUtil.validate(
      teamCreateDtoValidatorPreChecking(),
      dto,
    );

    if (validatedDataBasic.createOwnerAccount) {
      const validated = ValidationUtil.validate(
        teamAndUserCreateDtoValidator(),
        dto,
      );

      const { user, team } = await this.usersService.createUserWithTeam(
        validated,
        requesterUid,
        {
          lang:
            req.headers['accept-language'] ??
            req.headers['content-language'] ??
            null,
        },
      );

      return {
        team: team,
        user: user,
      };
    } else {
      const { user, team } =
        await this.teamsService.createTeam(validatedDataBasic);
      return {
        team: team,
        user: user,
      };
    }
  }

  @ApiOperation({
    summary:
      '[superuser][admin,write] Creates a new team plan (for super admins)',
    description: '',
    tags: ['team-plan'],
  })
  @UseGuards(new SuperAdminAccessGuard('admin', 'write'))
  @CodedMethod('CTP')
  @Post(':teamId/team-plans')
  async createTeamPlan(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Body() dto: TeamPlanCreateDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      teamPlanCreateDtoValidator(),
      dto,
    );

    const result = await this.teamsService.createTeamPlan(
      targetTeamId,
      validated,
    );
    return {
      team: result.team,
    };
  }

  @ApiOperation({
