import { ExecutionContext, Logger } from '@nestjs/common';
import _ from 'lodash';
import { Observable } from 'rxjs';

import { Coded, CodedMethod } from '@/app/common/decorators';
import { AppExtendedRequest } from '@/app/common/types';
import { CodedForbiddenException } from '@/app/exceptions/errors/coded-forbidden.exception';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';

import { BaseGuard } from './base.guard';

/**
 * Strongly restrict access only for super admins for special Apis.
 */
@Coded('GSAAC')
export class SuperAdminAccessGuard extends BaseGuard {
  private readonly logger = new Logger(SuperAdminAccessGuard.name);

  constructor(
    private readonly domain: 'basic' | 'management' | 'admin',
    private readonly level: 'read' | 'write' | 'admin',
  ) {
    super();
  }

  static ERROR_CODES = {
    INVALID_ROLE: ErrorInfo.getBuilder('IR', 'invalid_role_for_this_user'),
  };

  get EC() {
    return SuperAdminAccessGuard.ERROR_CODES;
  }

  @CodedMethod('CA')
  canActivate(
    context: ExecutionContext,
  ): boolean | Promise<boolean> | Observable<boolean> {
    const cbuilder = this.getCodeBuilder();
    const request = context.switchToHttp().getRequest<AppExtendedRequest>();

    const { roleChecker } = request.appExtension.auth!;

    if (
      !roleChecker.checkForSuperUser(
        this.domain,
