void _expectUserInfoFromUserData(UserInfo actual, UserData expected) {
  expect(actual.id, expected.id);
  expect(actual.email, expected.email);

  _expectProfileFromUserData(actual.profile, expected);
  _expectAccessibleContentsFromUserData(actual.accessibleContents, expected);
  _expectTeamsFromUserData(actual.teams, expected);
  _expectGivenUserRolesFromUserData(actual.givenUserRoles, expected);
}

void _expectProfileFromUserData(Profile actual, UserData expected) {
  expect(actual.id, expected.id);
  expect(actual.username, expected.name);
}

void _expectAccessibleContentsFromUserData(
    UserAccessibleContents actual, UserData expected) {
  final expectedAccessibleContents = createAccessibleContents(expected.roles
      .map((teamId, roles) =>
          MapEntry(teamId, roles.map((role) => role.name).toList())));
  expect(actual, expectedAccessibleContents);
}

void _expectTeamsFromUserData(List<Team> actual, UserData expected) {
  _expectList(
      actual,
      expected.roles.keys
          .map((teamId) => teamRecords.data.where((team) => team.id == teamId))
          .flattened
          .toList(),
      _expectTeam);
}

