import { Exclude, Expose } from 'class-transformer';
import _ from 'lodash';
import {
  Column,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  PrimaryGeneratedColumn,
} from 'typeorm';

import { ShortRoleInfo } from '@/app/common/types';

import { RoleDomain, roleDomains, RoleLevel } from './role';
import { RoleGroup } from './role-group';
import { Team } from './team';
import { User } from './user';

export type AppRole =
  | 'team_admin'
  | 'team_manager'
  | 'team_member'
  | 'personal_user'
  | 'super_admin'
  | 'super_reader';

@Index('user_roles_pkey', ['id'], { unique: true })
@Index('user_roles_user_id_idx', ['userId'], {})
@Entity('user_roles', { schema: 'public' })
export class UserRole {
  @PrimaryGeneratedColumn('uuid', { name: 'id' })
  id: string;

  @Column('uuid', { name: 'user_id' })
  userId: string;

  @Column('uuid', { name: 'team_id' })
  teamId: string;

  @Column('uuid', { name: 'role_group_id' })
  roleGroupId: string;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @Column('boolean', { name: 'delete_flag' })
  deleteFlag: boolean;

  @ManyToOne(() => User, (user) => user.userRoles)
  @JoinColumn([{ name: 'user_id', referencedColumnName: 'id' }])
  user: User;

  @ManyToOne(() => Team, (team) => team.userRoles)
  @JoinColumn([{ name: 'team_id', referencedColumnName: 'id' }])
  team: Team;

  @ManyToOne(() => RoleGroup, (user) => user.userRoles)
  @JoinColumn([{ name: 'role_group_id', referencedColumnName: 'id' }])
  roleGroup: RoleGroup;

  static readonly defaultLevelMap: Record<RoleLevel, ShortRoleInfo> =
    Object.freeze({
      read: {
        isAccessible: false,
        isTeamCrossing: false,
      },
      write: {
        isAccessible: false,
        isTeamCrossing: false,
      },
      admin: {
        isAccessible: false,
        isTeamCrossing: false,
      },
    });

  /**
   * Creates domain-level-shortrole nested map for UserRoles of a team, including all domains and levels.
   * @param userRoles team-filtered UserRole[]
   * @returns
   */
  static createDomainAndLevelMap(
    userRoles: UserRole[],
  ): Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>> {
    const ret = _.chain(roleDomains)
      .invert()
      .mapValues((x) => _.cloneDeep(UserRole.defaultLevelMap))
      .value() as Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>>;

    for (const userRole of userRoles) {
      for (const role of userRole.roleGroup.roles) {
        const levelMap = ret[role.domain];
        levelMap[role.level].isAccessible = true;
        levelMap[role.level].isTeamCrossing = role.isTeamCrossing;
        // read < write < admin
        if (role.level == 'write' || role.level == 'admin') {
          levelMap.read.isAccessible = true;
          levelMap.read.isTeamCrossing =
            levelMap.read.isTeamCrossing || role.isTeamCrossing;
        }
        if (role.level == 'admin') {
          levelMap.write.isAccessible = true;
          levelMap.write.isTeamCrossing =
            levelMap.write.isTeamCrossing || role.isTeamCrossing;
        }
      }
    }
    return ret;
  }

  static mergeDomainAndLevelMap(
    map1: Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>>,
    map2: Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>>,
  ) {
    const ret = _.chain(roleDomains)
      .invert()
      .mapValues((x) => _.cloneDeep(UserRole.defaultLevelMap))
      .value() as Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>>;
    for (const domain in ret) {
      for (const level in ret[domain]) {
        ret[domain][level].isAccessible =
          map1[domain][level].isAccessible || map2[domain][level].isAccessible;
        ret[domain][level].isTeamCrossing =
          map1[domain][level].isTeamCrossing ||
          map2[domain][level].isTeamCrossing;
      }
    }
    return ret;
  }
}

