import { Request } from 'express';
import _ from 'lodash';

import { Role, RoleDomain, RoleLevel } from '@/app/models/role';

export type UserRoleMap = {
  isTeamAdmin: boolean;
  isTeamManager: boolean;
  isTeamMember: boolean;
  isPersonalUser: boolean;
  isSuperAdmin: boolean;
};

export type ShortRoleInfo = {
  isAccessible: boolean;
  isTeamCrossing: boolean;
};

export class RoleChecker {
  constructor(
    private readonly teamDomainRolesMap: Record<
      string,
      Record<RoleDomain, Record<RoleLevel, ShortRoleInfo>>
    >,
    private readonly allTeamsDomainRolesMap: Record<
      RoleDomain,
      Record<RoleLevel, ShortRoleInfo>
    >,
    private readonly allTeamIds: string[],
  ) {
    //
  }

  check(
    teamId: string,
    domain: RoleDomain,
    level: RoleLevel,
    crossTeam: boolean,
  ): boolean {
    const superTeamRole = this.allTeamsDomainRolesMap[domain][level] ?? null;
    const roleMapInTeam = this.teamDomainRolesMap[teamId];
    const teamRole = roleMapInTeam ? roleMapInTeam[domain][level] : null;

    if (!roleMapInTeam && superTeamRole && !this.allTeamIds.includes(teamId)) {
      // superuser but teamId is not allowed
      return false;
    }

    if (!superTeamRole?.isAccessible && !teamRole?.isAccessible) {
      // no domain-matched roles
      return false;
    }

    if (
      crossTeam &&
      !superTeamRole?.isTeamCrossing &&
      !teamRole?.isTeamCrossing
    ) {
      // has domain-matched roles but it is not a in-team-crossing one
      return false;
    }

    return true;
  }

  checkForSuperUser(domain: RoleDomain, level: RoleLevel, teamId?: string) {
    return (
      this.allTeamsDomainRolesMap[domain][level]?.isAccessible &&
      (_.isNil(teamId) || this.allTeamIds.includes(teamId))
    );
  }
}

export type AppExtendedRequestData = {
  auth?: {
    // User ID of the authorized user
    requesterUid: string;

    // {team: {domain: levels}}
    roleChecker: RoleChecker;
    // requesterTeamId: string | null
    // // user_roles
    // userRoleMap: UserRoleMap

    accessToken: string;
  };
  apiVersion: number;
};

/**
 * Request & Additional data for this app.
 */
export type AppExtendedRequest = Request & {
  appExtension: AppExtendedRequestData;
  rawBody: Buffer;
};

export type ValidationEnumType<T> = readonly [T, ...T[]];

