import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

Future<bool> Function(Player player, String userId) usePlayerEditAccess() {
  final ref = useWidgetRef();
  final handleAccessDenied = useAccessDeniedNavigation();

  return (Player player, String userId) async {
    final accessibleContents = await ref
        .read(userAccessibleContentsControllerProvider.notifier)
        .refresh();

    final isEditable = accessibleContents != null
        ? player.isEditableByUser(userId, accessibleContents)
        : false;
    if (!isEditable) {
      handleAccessDenied();
      return false;
    }
    return true;
  };
}

